code_examples.insecureCode:
// ❌ Insecure: Fetches data based ONLY on the provided ID
app.get('/api/orders/:id', (req, res) => {
  const order = db.findOrder(req.params.id);
  // VULNERABILITY: No check if req.user.id matches order.userId
  res.json(order);
});

code_examples.secureCode:
// ✓ Secure: Validates ownership during the query
app.get('/api/orders/:id', (req, res) => {
  const order = db.findOrder(req.params.id);

  if (!order || order.userId !== req.user.id) {
    return res.status(403).json({
      error: 'Unauthorized: You do not own this resource.'
    });
  }

  res.json(order);
});
